    [Fact]
    public async Task FlaggedWorkBundle_Deleted_OnReAdd()
    {
        using var repo = TestRepository.Create();
        TestGit.Run(repo.Root, "init");
        TestGit.Run(repo.Root, "config", "user.email", "test@test");
        TestGit.Run(repo.Root, "config", "user.name", "Test");
        File.WriteAllText(Path.Combine(repo.Root, "README.md"), "# Test");
        TestGit.Run(repo.Root, "add", "README.md");
        TestGit.Run(repo.Root, "commit", "-m", "initial");

        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("readd-me", "# Original task\n");

        // Run 1: flag at stage 6.
        var fileWriter1 = new FileWritingSubagentRunner(writeAtStage: 5, file: "tests/my.test");
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: fileWriter1);
        var driver1 = new RelayDriver(
            RelayDriverDependencies.ForTests(flagger, new ScriptedTestRunner(
                new TestRunResult(1, "red")), new InMemoryRelayEventSink()),
            new RelayDriverOptions(CreateGitCommit: true));

        await driver1.RunTaskAsync(repo.Root, "readd-me");

        var taskDir = Path.Combine(repo.Root, ".relay", "readd-me");
        Assert.True(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")));

        // Simulate re-add: overwrite the task .md with new content.
        repo.WriteTask("readd-me", "# Completely new task — different content\n");

        // Run 2: resume → re-add detection triggers, old state archived, bundle gone.
        var capturing = new CapturingSubagentRunner();
        capturing.SeedHappyPath("src/status.cs", "tests/status.tests.cs");
        var driver2 = new RelayDriver(
            RelayDriverDependencies.ForTests(capturing,
                new ScriptedTestRunner(
                    new TestRunResult(1, "red"),
                    new TestRunResult(0, "green")),
                new InMemoryRelayEventSink()),
            new RelayDriverOptions(CreateGitCommit: true, Resume: true));

        await driver2.RunTaskAsync(repo.Root, "readd-me");

        // The bundle in the OLD task directory may still exist (archived), but
        // the NEW task directory must NOT have a stale bundle.
        Assert.False(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")),
            "stale flagged-work.bundle should be deleted when task is re-added");
        Assert.False(File.Exists(Path.Combine(taskDir, "flagged-work.json")),
            "stale flagged-work.json should be deleted when task is re-added");
    }

    /// <summary>
    /// Writes a specified file (and content) to the target root at a given stage,
    /// then delegates to <see cref="ScriptedSubagentRunner"/> for JSON responses.
    /// </summary>
    private sealed class FileWritingSubagentRunner : ISubagentRunner
    {
        private readonly int _writeAtStage;
        private readonly string _file;
        private readonly string _content;
        private readonly ScriptedSubagentRunner _inner = new();

        public FileWritingSubagentRunner(int writeAtStage, string file, string? content = null)
        {
            _writeAtStage = writeAtStage;
            _file = file;
            _content = content ?? "authored content";
        }

        public async Task<SubagentResult> RunAsync(
            StageInvocation invocation, CancellationToken cancellationToken = default)
        {
            if (invocation.Stage.Number == _writeAtStage)
            {
                var fullPath = Path.Combine(invocation.TargetRoot, _file);
                Directory.CreateDirectory(Path.GetDirectoryName(fullPath)!);
                await File.WriteAllTextAsync(fullPath, _content, cancellationToken);
            }

            return await _inner.RunAsync(invocation, cancellationToken);
        }
    }
}

using VisualRelay.App.ViewModels;
using VisualRelay.Domain;

namespace VisualRelay.Tests;

public sealed partial class MainWindowViewModelTests
{
    [Fact]
    public void ResumeSelectedCommand_CanExecute_False_WhenNoTaskSelected()
    {
        var viewModel = new MainWindowViewModel();
        Assert.False(viewModel.ResumeSelectedCommand.CanExecute(null));
    }

    [Fact]
    public void ResumeSelectedCommand_CanExecute_True_WhenNonArchivedTaskSelected()
    {
        var viewModel = new MainWindowViewModel();
        viewModel.Tasks.Add(new TaskRowViewModel(
            new RelayTaskItem("alpha", "/tmp/llm-tasks/alpha.md", "/tmp/llm-tasks", false, [])));
        viewModel.SelectedTask = viewModel.Tasks[0];

        Assert.True(viewModel.ResumeSelectedCommand.CanExecute(null));
    }

    [Fact]
    public void ResumeSelectedCommand_CanExecute_False_WhenArchivedTaskSelected()
    {
        var viewModel = new MainWindowViewModel();
        viewModel.Tasks.Add(new TaskRowViewModel(
            new RelayTaskItem("done-1", "/tmp/llm-tasks/completed/done-1.md", "/tmp/llm-tasks", false, [])));
        // Mark as archived — archived tasks are not runnable.
        viewModel.SelectedTask = viewModel.Tasks[0];
        viewModel.ShowArchive = true;

        // When viewing archive, CanRunSelected returns false (and so does Resume).
        Assert.False(viewModel.ResumeSelectedCommand.CanExecute(null));
    }

    [Fact]
    public void ResumeSelectedCommand_CanExecute_False_WhenPauseRequested()
    {
        var viewModel = new MainWindowViewModel();
        viewModel.Tasks.Add(new TaskRowViewModel(
            new RelayTaskItem("alpha", "/tmp/llm-tasks/alpha.md", "/tmp/llm-tasks", false, [])));
        viewModel.SelectedTask = viewModel.Tasks[0];
        viewModel.PauseRequested = true;

        Assert.False(viewModel.ResumeSelectedCommand.CanExecute(null));
    }

    [Fact]
    public void ResumeSelectedCommand_CanExecute_False_WhenBusy()
    {
        var viewModel = new MainWindowViewModel();
        viewModel.Tasks.Add(new TaskRowViewModel(
            new RelayTaskItem("alpha", "/tmp/llm-tasks/alpha.md", "/tmp/llm-tasks", false, [])));
        viewModel.SelectedTask = viewModel.Tasks[0];
        viewModel.IsBusy = true;

        Assert.False(viewModel.ResumeSelectedCommand.CanExecute(null));
    }
}

