using VisualRelay.Core.Execution;
using VisualRelay.Domain;

namespace VisualRelay.Tests;

public sealed partial class RelayDriverResumeTests
{
    [Fact]
    public async Task FlagAsync_CreatesFlaggedWorkBundle_WhenMidPipelineStageFlags()
    {
        using var repo = CreateGitRepo();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("snapshot-me", "# Snapshot me\n");

        var fileWriter = new FileWritingSubagentRunner(writeAtStage: 5, file: "tests/my.test");
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: fileWriter);
        var driver = MakeDriver(flagger, CreateGitCommit: true);

        var outcome = await driver.RunTaskAsync(repo.Root, "snapshot-me");
        Assert.Equal(RelayTaskOutcomeStatus.Flagged, outcome.Status);

        var taskDir = Path.Combine(repo.Root, ".relay", "snapshot-me");
        Assert.True(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")),
            "flagged-work.bundle should be created at flag time");
        Assert.True(File.Exists(Path.Combine(taskDir, "flagged-work.json")),
            "flagged-work.json sidecar should be created");

        // git status must be clean (bundle is gitignored under .relay/*).
        Assert.Empty(TestGit.Run(repo.Root, "status", "--porcelain").Trim());
    }

    [Fact]
    public async Task Resume_RestoresWork_WhenBundleExistsAndBaseReachable()
    {
        using var repo = CreateGitRepo();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("restore-me", "# Restore me\n");

        // Run 1: write feature file, flag at stage 6.
        var fileWriter = new FileWritingSubagentRunner(writeAtStage: 5, file: "tests/my.test");
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: fileWriter);
        var outcome1 = await MakeDriver(flagger, CreateGitCommit: true)
            .RunTaskAsync(repo.Root, "restore-me");
        Assert.Equal(RelayTaskOutcomeStatus.Flagged, outcome1.Status);
        Assert.True(File.Exists(Path.Combine(repo.Root, ".relay", "restore-me", "flagged-work.bundle")));

        // Feature file must be gone after WorktreeResetter reset.
        Assert.False(File.Exists(Path.Combine(repo.Root, "tests", "my.test")));

        // Run 2: resume — the bundle should restore the file.
        var capturing = new CapturingSubagentRunner();
        capturing.SeedHappyPath("src/status.cs", "tests/status.tests.cs");
        var driver2 = MakeDriver(capturing, CreateGitCommit: true, Resume: true);
        var outcome2 = await driver2.RunTaskAsync(repo.Root, "restore-me");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome2.Status);

        Assert.True(File.Exists(Path.Combine(repo.Root, "tests", "my.test")),
            "feature file should be restored from flagged-work bundle on resume");
        Assert.Contains(capturing.Invocations, inv => inv.Stage.Number == 6);
        Assert.DoesNotContain(capturing.Invocations, inv => inv.Stage.Number <= 5);
    }

    [Fact]
    public async Task Resume_RestoresWork_OntoAdvancedBase()
    {
        using var repo = CreateGitRepo();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("advance-me", "# Advance me\n");

        var fileWriter = new FileWritingSubagentRunner(writeAtStage: 5, file: "tests/my.test");
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: fileWriter);
        await MakeDriver(flagger, CreateGitCommit: true)
            .RunTaskAsync(repo.Root, "advance-me");

        // Advance HEAD with an unrelated commit.
        File.WriteAllText(Path.Combine(repo.Root, "unrelated.txt"), "unrelated");
        TestGit.Run(repo.Root, "add", "unrelated.txt");
        TestGit.Run(repo.Root, "commit", "-m", "unrelated change");

        var capturing = new CapturingSubagentRunner();
        capturing.SeedHappyPath("src/status.cs", "tests/status.tests.cs");
        var outcome = await MakeDriver(capturing, CreateGitCommit: true, Resume: true)
            .RunTaskAsync(repo.Root, "advance-me");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome.Status);

        Assert.True(File.Exists(Path.Combine(repo.Root, "tests", "my.test")));
        Assert.True(File.Exists(Path.Combine(repo.Root, "unrelated.txt")));
    }

    [Fact]
    public async Task Resume_ProducesConflicts_WhenUpstreamOverlaps()
    {
        using var repo = CreateGitRepo();

        // Seed a file both the task and the upstream commit will touch.
        Directory.CreateDirectory(Path.Combine(repo.Root, "src"));
        File.WriteAllText(Path.Combine(repo.Root, "src", "Foo.cs"), "original");
        TestGit.Run(repo.Root, "add", "src/Foo.cs");
        TestGit.Run(repo.Root, "commit", "-m", "initial");

        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("conflict-me", "# Conflict me\n");
        const string taskAuthored = "task-authored version of Foo.cs";

        var overwriter = new FileWritingSubagentRunner(
            writeAtStage: 5, file: "src/Foo.cs", content: taskAuthored);
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: overwriter);
        await MakeDriver(flagger, CreateGitCommit: true)
            .RunTaskAsync(repo.Root, "conflict-me");

        // Advance HEAD with a conflicting edit.
        File.WriteAllText(Path.Combine(repo.Root, "src", "Foo.cs"), "upstream conflicting edit");
        TestGit.Run(repo.Root, "add", "src/Foo.cs");
        TestGit.Run(repo.Root, "commit", "-m", "upstream change to Foo.cs");

        var capturing = new CapturingSubagentRunner();
        capturing.SeedHappyPath("src/status.cs", "tests/status.tests.cs");
        var outcome = await MakeDriver(capturing, CreateGitCommit: true, Resume: true)
            .RunTaskAsync(repo.Root, "conflict-me");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome.Status);

        var fooContent = File.ReadAllText(Path.Combine(repo.Root, "src", "Foo.cs"));
        Assert.DoesNotContain("<<<<<<<", fooContent);
        Assert.DoesNotContain("=======", fooContent);
        Assert.DoesNotContain(">>>>>>>", fooContent);
        // Without restore the file still holds "upstream conflicting edit".
        Assert.Contains(taskAuthored, fooContent);
    }

    [Fact]
    public async Task FlaggedWorkBundle_Deleted_OnSuccessfulCommit()
    {
        using var repo = CreateGitRepo();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("cleanup-me", "# Cleanup me\n");

        var fileWriter = new FileWritingSubagentRunner(writeAtStage: 5, file: "tests/my.test");
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: fileWriter);
        await MakeDriver(flagger, CreateGitCommit: true)
            .RunTaskAsync(repo.Root, "cleanup-me");

        var taskDir = Path.Combine(repo.Root, ".relay", "cleanup-me");
        Assert.True(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")));

        var capturing = new CapturingSubagentRunner();
        capturing.SeedHappyPath("src/status.cs", "tests/status.tests.cs");
        var outcome = await MakeDriver(capturing, CreateGitCommit: true, Resume: true)
            .RunTaskAsync(repo.Root, "cleanup-me");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome.Status);

        Assert.False(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")),
            "flagged-work.bundle should be deleted after successful commit");
        Assert.False(File.Exists(Path.Combine(taskDir, "flagged-work.json")),
            "flagged-work.json should be deleted after successful commit");
    }

    [Fact]
    public async Task FlaggedWorkBundle_Deleted_OnReAdd()
    {
        using var repo = CreateGitRepo();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("readd-me", "# Original task\n");

        var fileWriter = new FileWritingSubagentRunner(writeAtStage: 5, file: "tests/my.test");
        var flagger = new FlagAtStageSubagentRunner(flagAtStage: 6, inner: fileWriter);
        await MakeDriver(flagger, CreateGitCommit: true)
            .RunTaskAsync(repo.Root, "readd-me");

        var taskDir = Path.Combine(repo.Root, ".relay", "readd-me");
        Assert.True(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")));

        // Simulate re-add: overwrite task markdown.
        repo.WriteTask("readd-me", "# Completely new task\n");

        var capturing = new CapturingSubagentRunner();
        capturing.SeedHappyPath("src/status.cs", "tests/status.tests.cs");
        await MakeDriver(capturing, CreateGitCommit: true, Resume: true)
            .RunTaskAsync(repo.Root, "readd-me");

        Assert.False(File.Exists(Path.Combine(taskDir, "flagged-work.bundle")),
            "stale flagged-work.bundle should be deleted when task is re-added");
        Assert.False(File.Exists(Path.Combine(taskDir, "flagged-work.json")),
            "stale flagged-work.json should be deleted when task is re-added");
    }

    // ---- helpers ----

    private static TestRepository CreateGitRepo()
    {
        var repo = TestRepository.Create();
        TestGit.Run(repo.Root, "init");
        TestGit.Run(repo.Root, "config", "user.email", "test@test");
        TestGit.Run(repo.Root, "config", "user.name", "Test");
        File.WriteAllText(Path.Combine(repo.Root, "README.md"), "# Test");
        TestGit.Run(repo.Root, "add", "README.md");
        TestGit.Run(repo.Root, "commit", "-m", "initial");
        return repo;
    }

    private static RelayDriver MakeDriver(ISubagentRunner subagents,
        bool CreateGitCommit = false, bool Resume = false)
    {
        var deps = RelayDriverDependencies.ForTests(
            subagents,
            new ScriptedTestRunner(
                new TestRunResult(1, "red"),
                new TestRunResult(0, "green")),
            new InMemoryRelayEventSink());
        return new RelayDriver(deps,
            new RelayDriverOptions(CreateGitCommit: CreateGitCommit, Resume: Resume));
    }

    private sealed class FileWritingSubagentRunner : ISubagentRunner
    {
        private readonly int _writeAtStage;
        private readonly string _file;
        private readonly string _content;
        private readonly ScriptedSubagentRunner _inner = new();

        public FileWritingSubagentRunner(int writeAtStage, string file, string? content = null)
        {
            _writeAtStage = writeAtStage;
            _file = file;
            _content = content ?? "authored content";
        }

        public async Task<SubagentResult> RunAsync(
            StageInvocation invocation, CancellationToken ct = default)
        {
            if (invocation.Stage.Number == _writeAtStage)
            {
                var fullPath = Path.Combine(invocation.TargetRoot, _file);
                Directory.CreateDirectory(Path.GetDirectoryName(fullPath)!);
                await File.WriteAllTextAsync(fullPath, _content, ct);
            }
            return await _inner.RunAsync(invocation, ct);
        }
    }
}
